// // This D flip-flop stores the data input on the falling edge of the clock and resets to 1 when the reset signal is inactive.
module d_flip_flop(
	input wire d,
	input wire clk,
	input wire rst,
	output reg q
);

always @(posedge clk or posedge rst) begin
	if (rst) begin
		q <= 1'b0;
	end else begin
		q <= d;
	end
end

endmodule
